class LRUCache {
public:
    LRUCache(int capacity) : capacity_(capacity) {}

    int get(int key) {
        auto it = cache_.find(key);
        if (it == cache_.end()) {
            return -1;
        }
        int value = it->second.first;
        cache_.erase(it);
        cache_[key] = {value, ++timestamp_};
        return value;
    }

    void put(int key, int value) {
        auto it = cache_.find(key);
        if (it != cache_.end()) {
            cache_.erase(it);
        } else if (cache_.size() == capacity_) {
            int lru_key = -1;
            int min_timestamp = INT_MAX;
            for (const auto& pair : cache_) {
                if (pair.second.second < min_timestamp) {
                    min_timestamp = pair.second.second;
                    lru_key = pair.first;
                }
            }
            cache_.erase(lru_key);
        }
        cache_[key] = {value, ++timestamp_};
    }
private:
    int capacity_;
    std::unordered_map<int, std::pair<int, int>> cache_;
    int timestamp_ = 0;
};

